after_code:
// schemas.ts
import { z } from 'zod';

export const UserSchema = z.object({
  id: z.string().uuid(),  // now validates UUID format
  email: z.string().email(),
  name: z.string().min(1),
});

export type User = z.infer<typeof UserSchema>;
